import AppKit
import SwiftUI

struct BenchmarkView: View {
    @Bindable var controller: BenchmarkController

    @State private var exportToastVisible: Bool = false

    var body: some View {
        ScrollView {
            VStack(alignment: .leading, spacing: 18) {
                setupSection
                Divider()
                if controller.isRunning {
                    progressSection
                } else if !controller.history.isEmpty {
                    reportArea
                } else if let err = controller.errorMessage {
                    Text(err)
                        .font(.callout)
                        .foregroundStyle(.red)
                } else {
                    placeholderSection
                }
            }
            .frame(maxWidth: 880, alignment: .leading)
            .padding(20)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .onChange(of: controller.lastExportPath) { _, newValue in
            guard newValue != nil else { return }
            exportToastVisible = true
            Task {
                try? await Task.sleep(nanoseconds: 2_500_000_000)
                await MainActor.run { exportToastVisible = false }
            }
        }
    }

    // MARK: - Setup

    @ViewBuilder
    private var setupSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            sectionHeader("Setup")
            HStack(spacing: 12) {
                LabeledContent(String(localized: "Model")) {
                    Picker("", selection: $controller.selectedProfile) {
                        ForEach(ModelProfile.allCases) { p in
                            Text(p.displayName).tag(p)
                        }
                    }
                    .pickerStyle(.menu)
                    .labelsHidden()
                }
                LabeledContent(String(localized: "Output style")) {
                    Picker("", selection: $controller.selectedPreference) {
                        ForEach(ChinesePreference.allCases) { c in
                            Text(c.displayName).tag(c)
                        }
                    }
                    .pickerStyle(.menu)
                    .labelsHidden()
                }
                Spacer()
                Button {
                    controller.run()
                } label: {
                    Label(String(localized: "Run benchmark"), systemImage: "gauge.with.dots.needle.50percent")
                }
                .buttonStyle(.borderedProminent)
                .disabled(controller.isRunning)
                if controller.isRunning {
                    Button(role: .destructive) {
                        controller.cancel()
                    } label: {
                        Label(String(localized: "Cancel"), systemImage: "stop.fill")
                    }
                }
            }
        }
    }

    // MARK: - Progress

    @ViewBuilder
    private var progressSection: some View {
        VStack(alignment: .leading, spacing: 8) {
            sectionHeader("Running")
            ProgressView(value: controller.progressFraction)
                .progressViewStyle(.linear)
            HStack {
                Text("\(controller.progressCompleted) / \(controller.progressTotal)")
                    .font(.caption.monospacedDigit())
                Spacer()
                if let id = controller.currentRecordID {
                    Text("Current: \(id)")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                        .lineLimit(1)
                        .truncationMode(.middle)
                }
            }
        }
    }

    // MARK: - Report

    @ViewBuilder
    private var reportArea: some View {
        VStack(alignment: .leading, spacing: 14) {
            historyBar
            if let report = controller.displayedReport {
                reportSection(report)
            }
        }
    }

    @ViewBuilder
    private var historyBar: some View {
        if controller.history.count > 1 {
            HStack(spacing: 6) {
                Text("Run")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(.secondary)
                Picker("", selection: Binding(
                    get: { controller.displayedRunAt ?? controller.history.first?.runAt ?? "" },
                    set: { controller.displayedRunAt = $0 }
                )) {
                    ForEach(controller.history, id: \.runAt) { r in
                        Text(historyLabel(r)).tag(r.runAt)
                    }
                }
                .pickerStyle(.menu)
                .labelsHidden()
                .frame(maxWidth: 400)
                Spacer()
            }
        }
    }

    private func historyLabel(_ report: BenchmarkReport) -> String {
        let f = DateFormatter()
        f.timeStyle = .short
        let iso = ISO8601DateFormatter()
        iso.formatOptions = [.withInternetDateTime]
        let timeText = iso.date(from: report.runAt).map { f.string(from: $0) } ?? report.runAt
        let modelShort = report.modelID.components(separatedBy: "/").last ?? report.modelID
        return "\(timeText) · \(modelShort)"
    }

    @ViewBuilder
    private func reportSection(_ report: BenchmarkReport) -> some View {
        VStack(alignment: .leading, spacing: 12) {
            HStack {
                sectionHeader("Results")
                if exportToastVisible {
                    HStack(spacing: 3) {
                        Image(systemName: "checkmark.circle.fill").imageScale(.small)
                        Text("Exported")
                    }
                    .font(.caption)
                    .foregroundStyle(.green)
                    .transition(.opacity)
                }
                Spacer()
                Button {
                    exportReport(report)
                } label: {
                    Label(String(localized: "Export JSON"), systemImage: "square.and.arrow.up")
                }
                .controlSize(.small)
            }
            .animation(.easeOut(duration: 0.2), value: exportToastVisible)

            summaryGrid(report)

            metricsToggleBar

            cerLegend

            Divider()

            VStack(alignment: .leading, spacing: 6) {
                ForEach(report.results) { r in
                    resultRow(r)
                }
            }
        }
    }

    @ViewBuilder
    private func summaryGrid(_ report: BenchmarkReport) -> some View {
        let useNorm = controller.useNormalizedMetrics
        Grid(alignment: .leading, horizontalSpacing: 24, verticalSpacing: 6) {
            GridRow {
                summaryCell(label: String(localized: "Model"), value: report.modelID)
                summaryCell(label: String(localized: "Output style"), value: report.chinesePreference.displayName)
            }
            GridRow {
                summaryCell(label: String(localized: "Total"), value: "\(report.total)")
                summaryCell(
                    label: String(localized: "Exact match"),
                    value: "\(report.exactMatchCount(useNormalized: useNorm)) (\(String(format: "%.1f%%", report.exactMatchRate(useNormalized: useNorm) * 100)))"
                )
            }
            GridRow {
                summaryCell(
                    label: String(localized: "Avg CER"),
                    value: String(format: "%.3f", report.averageCER(useNormalized: useNorm)),
                    tooltip: String(localized: "Character Error Rate — 0 means perfect, lower is better.")
                )
                summaryCell(label: String(localized: "Avg latency"), value: "\(report.averageLatencyMs) ms")
            }
            if report.failed > 0 {
                GridRow {
                    summaryCell(label: String(localized: "Failed"), value: "\(report.failed)", tone: .red)
                }
            }
        }
    }

    @ViewBuilder
    private var metricsToggleBar: some View {
        HStack(spacing: 8) {
            Toggle(isOn: $controller.useNormalizedMetrics) {
                Text("Normalize (lowercase + strip punctuation + 全→半形)")
                    .font(.caption)
            }
            .toggleStyle(.switch)
            .controlSize(.mini)
            Spacer()
        }
    }

    @ViewBuilder
    private func summaryCell(label: String, value: String, tone: Color = .primary, tooltip: String? = nil) -> some View {
        VStack(alignment: .leading, spacing: 2) {
            HStack(spacing: 3) {
                Text(label)
                    .font(.caption)
                    .foregroundStyle(.secondary)
                if let tooltip {
                    Image(systemName: "info.circle")
                        .font(.caption2)
                        .foregroundStyle(.tertiary)
                        .help(tooltip)
                }
            }
            Text(value)
                .font(.body.monospacedDigit())
                .foregroundStyle(tone)
        }
    }

    @ViewBuilder
    private var cerLegend: some View {
        VStack(alignment: .leading, spacing: 4) {
            HStack(spacing: 14) {
                legendDot(.green, label: String(localized: "Exact"))
                legendDot(.yellow, label: String(localized: "CER < 0.1"))
                legendDot(.orange, label: String(localized: "0.1–0.3"))
                legendDot(.red, label: String(localized: "> 0.3"))
                HStack(spacing: 3) {
                    Image(systemName: "exclamationmark.triangle.fill")
                        .font(.caption2)
                        .foregroundStyle(.red)
                    Text("Error")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
                Spacer()
            }
            HStack(spacing: 14) {
                // Char-diff colors mirror git semantics relative to the ground truth.
                HStack(spacing: 4) {
                    Text("綠")
                        .font(.caption2)
                        .foregroundColor(.green)
                        .underline()
                    Text("Missing (model omitted)")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
                HStack(spacing: 4) {
                    Text("紅")
                        .font(.caption2)
                        .foregroundColor(.red)
                        .strikethrough()
                    Text("Extra (model hallucinated)")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }
                Spacer()
            }
        }
        .padding(.vertical, 4)
    }

    @ViewBuilder
    private func legendDot(_ color: Color, label: String) -> some View {
        HStack(spacing: 3) {
            Circle().fill(color).frame(width: 8, height: 8)
            Text(label)
                .font(.caption)
                .foregroundStyle(.secondary)
        }
    }

    @ViewBuilder
    private func resultRow(_ r: BenchmarkResult) -> some View {
        let useNorm = controller.useNormalizedMetrics
        let cerValue = r.cer(useNormalized: useNorm)
        let isExact = r.exactMatch(useNormalized: useNorm)
        VStack(alignment: .leading, spacing: 4) {
            HStack(spacing: 6) {
                Image(systemName: rowIcon(r, isExact: isExact))
                    .foregroundStyle(rowColor(r, cer: cerValue, isExact: isExact))
                    .imageScale(.small)
                Text(r.id)
                    .font(.caption.weight(.medium))
                Spacer()
                if r.error == nil {
                    Text("CER \(String(format: "%.2f", cerValue))")
                        .font(.caption.monospacedDigit())
                        .foregroundStyle(.secondary)
                    Text("\(r.durationMs) ms")
                        .font(.caption.monospacedDigit())
                        .foregroundStyle(.tertiary)
                }
            }
            if let err = r.error {
                Text(err)
                    .font(.caption2)
                    .foregroundStyle(.red)
                    .lineLimit(2)
            } else if isExact {
                Text(verbatim: r.predictedEdited)
                    .font(.caption2)
                    .foregroundStyle(.primary)
                    .lineLimit(2)
            } else {
                HStack(alignment: .top, spacing: 6) {
                    Text("Diff")
                        .font(.caption2.weight(.semibold))
                        .foregroundStyle(.secondary)
                        .frame(width: 36, alignment: .leading)
                    diffText(reference: r.groundTruth, hypothesis: r.predictedEdited)
                        .lineLimit(4)
                        .textSelection(.enabled)
                }
            }
        }
        .padding(.vertical, 4)
    }

    /// Renders a git-style colored diff: from the model's prediction toward the ground truth.
    ///   - equal chars: primary
    ///   - `.delete` (in truth, missing from prediction → prediction is **missing this**):
    ///     green underline. Read as "needs to be added".
    ///   - `.insert` (in prediction, not in truth → prediction **wrongly said this**):
    ///     red strikethrough. Read as "needs to be removed".
    private func diffText(reference: String, hypothesis: String) -> Text {
        let segments = TextDiff.diff(reference: reference, hypothesis: hypothesis)
        var out = Text("")
        for seg in segments {
            switch seg.op {
            case .equal:
                out = out + Text(seg.text).foregroundColor(.primary)
            case .delete:
                // Model omitted this — show in green as "should have been here".
                out = out + Text(seg.text)
                    .foregroundColor(.green)
                    .underline()
            case .insert:
                // Model hallucinated this — show in red as "shouldn't be here".
                out = out + Text(seg.text)
                    .foregroundColor(.red)
                    .strikethrough()
            }
        }
        return out.font(.caption2)
    }

    private func rowIcon(_ r: BenchmarkResult, isExact: Bool) -> String {
        if r.error != nil { return "exclamationmark.triangle.fill" }
        if isExact { return "checkmark.circle.fill" }
        return "circle.fill"
    }

    private func rowColor(_ r: BenchmarkResult, cer: Double, isExact: Bool) -> Color {
        if r.error != nil { return .red }
        if isExact { return .green }
        if cer < 0.1 { return .yellow }
        if cer < 0.3 { return .orange }
        return .red
    }

    // MARK: - Placeholder

    @ViewBuilder
    private var placeholderSection: some View {
        VStack(spacing: 8) {
            Image(systemName: "gauge.with.dots.needle.50percent")
                .font(.largeTitle)
                .foregroundStyle(.tertiary)
            Text("Run the full pipeline against every record")
                .font(.headline)
                .foregroundStyle(.secondary)
            Text("Compares the model's post-processed output with the saved edited transcript. Reports CER, exact-match rate, and average latency.")
                .font(.caption)
                .foregroundStyle(.secondary)
                .multilineTextAlignment(.center)
                .frame(maxWidth: 480)
        }
        .frame(maxWidth: .infinity)
        .padding(.vertical, 24)
    }

    @ViewBuilder
    private func sectionHeader(_ key: LocalizedStringKey) -> some View {
        Text(key)
            .font(.caption.weight(.semibold))
            .foregroundStyle(.secondary)
            .textCase(.uppercase)
    }

    // MARK: - Export

    private func exportReport(_ report: BenchmarkReport) {
        let panel = NSSavePanel()
        panel.allowedContentTypes = [.json]
        panel.nameFieldStringValue = "benchmark-\(report.modelID.replacingOccurrences(of: "/", with: "_")).json"
        panel.begin { response in
            guard response == .OK, let url = panel.url else { return }
            do {
                try controller.exportJSON(to: url)
            } catch {
                NSLog("ThinkAloud: benchmark export failed: \(error)")
            }
        }
    }
}

import Foundation
import Observation

@MainActor
@Observable
final class BenchmarkController {
    // Configuration (bound to UI pickers)
    var selectedProfile: ModelProfile
    var selectedPreference: ChinesePreference
    /// When true, CER / exact-match read the aggressive-normalized fields (Whisper-style:
    /// lowercase, strip punctuation, full→half width). When false, they use the strict fields
    /// (whitespace-only normalization). Pure view toggle — both metrics are always computed.
    var useNormalizedMetrics: Bool = true

    // Runtime state
    private(set) var isRunning: Bool = false
    private(set) var progressCompleted: Int = 0
    private(set) var progressTotal: Int = 0
    private(set) var currentRecordID: String?
    /// History of completed runs, newest first. Lets the user compare different model / preference
    /// configurations in one session. Cleared when the browser window closes.
    private(set) var history: [BenchmarkReport] = []
    /// The currently-displayed report from history. Defaults to the newest entry; user can switch.
    var displayedRunAt: String?
    private(set) var errorMessage: String?

    /// One-off feedback flag — view sets to nil after surfacing it.
    var lastExportPath: String?

    // Dependencies
    private let datasetStore: DatasetStore
    private let audioFileStore: AudioFileStore
    private let modelsDirectory: URL

    private var task: Task<Void, Never>?

    init(
        datasetStore: DatasetStore,
        audioFileStore: AudioFileStore,
        modelsDirectory: URL,
        initialProfile: ModelProfile,
        initialPreference: ChinesePreference
    ) {
        self.datasetStore = datasetStore
        self.audioFileStore = audioFileStore
        self.modelsDirectory = modelsDirectory
        self.selectedProfile = initialProfile
        self.selectedPreference = initialPreference
    }

    var progressFraction: Double {
        guard progressTotal > 0 else { return 0 }
        return Double(progressCompleted) / Double(progressTotal)
    }

    func run() {
        guard !isRunning else { return }
        let profile = selectedProfile
        let preference = selectedPreference
        let datasetStore = datasetStore
        let audioFileStore = audioFileStore
        let modelsDirectory = modelsDirectory

        isRunning = true
        errorMessage = nil
        progressCompleted = 0
        progressTotal = 0
        currentRecordID = nil

        task = Task { @MainActor [weak self] in
            defer {
                self?.isRunning = false
                self?.currentRecordID = nil
                self?.task = nil
            }
            do {
                let records = try await datasetStore.all()
                guard !records.isEmpty else {
                    self?.errorMessage = String(localized: "Dataset is empty — nothing to benchmark.")
                    return
                }
                self?.progressTotal = records.count

                // Transient runtime so the popup's active runtime is undisturbed. It will be
                // unloaded after the run completes.
                let runtime = ASRRuntimeFactory.make(profile: profile, cacheDirectory: modelsDirectory)
                do {
                    try await runtime.preload()
                } catch {
                    self?.errorMessage = String(localized: "Model preload failed: \(error.localizedDescription)")
                    return
                }

                let runner = BenchmarkRunner()
                let report: BenchmarkReport
                do {
                    report = try await runner.run(
                        records: records,
                        runtime: runtime,
                        chinesePreference: preference,
                        audioURLProvider: { record in
                            await audioFileStore.absoluteURL(for: record.audioPath)
                        },
                        progress: { [weak self] p in
                            await MainActor.run {
                                self?.progressCompleted = p.completed
                                self?.currentRecordID = p.currentRecordID.isEmpty ? nil : p.currentRecordID
                            }
                        }
                    )
                } catch is CancellationError {
                    await runtime.unload()
                    self?.errorMessage = String(localized: "Cancelled.")
                    return
                } catch {
                    await runtime.unload()
                    self?.errorMessage = String(localized: "Benchmark failed: \(error.localizedDescription)")
                    return
                }
                await runtime.unload()
                if let self {
                    self.history.insert(report, at: 0)
                    self.displayedRunAt = report.runAt
                }
            } catch {
                self?.errorMessage = String(localized: "Failed to load records: \(error.localizedDescription)")
            }
        }
    }

    func cancel() {
        task?.cancel()
    }

    /// The displayed report — either an explicit selection from history or the newest run.
    var displayedReport: BenchmarkReport? {
        if let runAt = displayedRunAt, let hit = history.first(where: { $0.runAt == runAt }) {
            return hit
        }
        return history.first
    }

    /// Encodes the displayed report to pretty-printed JSON and writes it to `url`.
    func exportJSON(to url: URL) throws {
        guard let report = displayedReport else {
            throw NSError(domain: "Benchmark", code: 1, userInfo: [NSLocalizedDescriptionKey: "No report to export"])
        }
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.prettyPrinted, .sortedKeys, .withoutEscapingSlashes]
        let data = try encoder.encode(report)
        try data.write(to: url, options: .atomic)
        lastExportPath = url.path
    }
}

import XCTest
@testable import ThinkAloud

final class TextMetricsTests: XCTestCase {
    func testEditDistanceBasics() {
        XCTAssertEqual(TextMetrics.editDistance("", ""), 0)
        XCTAssertEqual(TextMetrics.editDistance("abc", ""), 3)
        XCTAssertEqual(TextMetrics.editDistance("", "abc"), 3)
        XCTAssertEqual(TextMetrics.editDistance("kitten", "sitting"), 3)
        XCTAssertEqual(TextMetrics.editDistance("abc", "abc"), 0)
    }

    func testEditDistanceChineseCharacters() {
        XCTAssertEqual(TextMetrics.editDistance("會議重點", "會議結論"), 2)
        XCTAssertEqual(TextMetrics.editDistance("這是測試", "這是測試"), 0)
        XCTAssertEqual(TextMetrics.editDistance("這是測試", "這是錯誤的測試"), 3)
    }

    func testCERIsLengthNormalized() {
        // Perfect match → 0
        XCTAssertEqual(TextMetrics.cer(reference: "abc", hypothesis: "abc"), 0)
        // 1 substitution out of 3 chars → 1/3
